class Dog:
    def __init__(self, name):
        self.name = name

d = Dog('Rex')
print(d.name)

class Dog:
    def __init__(self, name):
        self.name = name
    def __str__(self):
        return f'Dog: {self.name}'

d = Dog('Rex')
print(d)

class Box:
    @staticmethod
    def info():
        return 'I am a box'

print(Box.info())

class Box:
    label = 'generic'

    @classmethod
    def change_label(cls, new_label):
        cls.label = new_label

Box.change_label('special')
print(Box.label)

class Person:
    def __init__(self, name):
        self.name = name

p = Person('Alice')
print(type(p))

class Dog:
    tricks = []
    def __init__(self, name):
        self.name = name
    def add_trick(self, trick):
        self.tricks.append(trick)

d1 = Dog('Rex')
d2 = Dog('Buddy')
d1.add_trick('sit')
print(d2.tricks)

class A:
    data = {}

a1 = A()
a2 = A()
a1.data['key'] = 'val'
print(a2.data)

